sql:
SELECT DISTINCT users.username, users.email
FROM users
INNER JOIN api_requests ON users.user_id = api_requests.user_id;

SELECT username
FROM users
WHERE role = 'researcher' AND user_id IN (SELECT DISTINCT user_id FROM error_logs);

SELECT d.sample_name
FROM datasets d
WHERE d.dataset_id NOT IN (
  SELECT dr.dataset_id
  FROM dataset_relationships dr
);

SELECT u.username
FROM users u
WHERE u.user_id IN (
    SELECT al.user_id
    FROM user_access_logs al
    WHERE al.access_time >= date('now', '-6 months')
) AND u.user_id NOT IN (
    SELECT du.user_id
    FROM data_uploads du
);

SELECT user_id, COUNT(*)
FROM api_requests
GROUP BY user_id;

